Here's exactly what I would change in `src/app.js`:

```javascript
// Current code (lines 6-10):
app.post('/users', async (req, res) => {
  const { name, email } = req.body;
  const result = await db('users').insert({ name, email });
  res.status(201).json({ id: result[0], name, email });
});

// Proposed change:
app.post('/users', async (req, res) => {
  const { name, email } = req.body;

  // Validate name
  if (typeof name !== 'string' || name.trim().length === 0) {
    return res.status(400).json({ error: 'Name must be a non-empty string' });
  }
  if (name.length > 100) {
    return res.status(400).json({ error: 'Name must be 100 characters or less' });
  }

  // Validate email
  if (typeof email !== 'string' || !email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) {
    return res.status(400).json({ error: 'Email must be a valid email address' });
  }

  const result = await db('users').insert({ name: name.trim(), email: email.trim() });
  res.status(201).json({ id: result[0], name: name.trim(), email: email.trim() });
});
```

The validation:
- **Name**: checks it's a string, non-empty after trimming, and max 100 characters
- **Email**: checks it's a string and matches a basic email pattern
- Returns 400 with descriptive error messages on validation failure
- Trims whitespace before insert and response

